if args.enable_ep_moe:
    allowed_ep_att_backends = {"auto", "fa3", "triton"}
    for backend in args.llm_prefill_att_backend:
        assert backend in allowed_ep_att_backends, (
            "When --enable_ep_moe is enabled, --llm_prefill_att_backend must be one of "
            f"{sorted(allowed_ep_att_backends)}; flashinfer is not supported."
        )
    for backend in args.llm_decode_att_backend:
        assert backend in allowed_ep_att_backends, (
            "When --enable_ep_moe is enabled, --llm_decode_att_backend must be one of "
            f"{sorted(allowed_ep_att_backends)}; flashinfer is not supported."
        )

# mtp params check
if args.mtp_mode is not None:
    assert args.mtp_draft_model_dir is not None
    assert args.mtp_step > 0
else:
    assert args.mtp_draft_model_dir is None
    assert args.mtp_step == 0

if args.afs_image_embed_dir is not None:
    os.makedirs(args.afs_image_embed_dir, mode=0o777, exist_ok=True)
    os.chmod(args.afs_image_embed_dir, 0o777)

# 检查GPU数量是否足够
if args.visual_gpu_ids is None:
    args.visual_gpu_ids = list(range(args.visual_dp * args.visual_tp))
total_required_gpus = args.visual_dp * args.visual_tp
if len(args.visual_gpu_ids) < total_required_gpus:
    raise ValueError(
        f"Not enough GPUs specified. You need at least {total_required_gpus}, but got {len(args.visual_gpu_ids)}."
    )
else:
    args.visual_gpu_ids = args.visual_gpu_ids[:total_required_gpus]

import torch

from lightllm.models.deepseek_mtp.layer_weights.pre_and_post_layer_weight import Deepseek3MTPPreAndPostLayerWeight
from lightllm.models.deepseek2.infer_struct import Deepseek2InferStateInfo
from lightllm.models.llama.layer_infer.pre_layer_infer import LlamaPreLayerInfer


class Deepseek3MTPPreLayerInfer(LlamaPreLayerInfer):
    """ """

    def __init__(self, network_config):
        super().__init__(network_config)
        self.eps_ = network_config["rms_norm_eps"]
        self.hidden_size = network_config["hidden_size"]
        return

    def _mtp_context_forward(
        self, input_embdings, infer_state: Deepseek2InferStateInfo, layer_weight: Deepseek3MTPPreAndPostLayerWeight
    ):
        tgt_embdings = infer_state.mtp_draft_input_hiddens
        assert (
            input_embdings.shape[0] == tgt_embdings.shape[0]
        ), f"shape {input_embdings.shape} != shape {tgt_embdings.shape}"

        layer_weight.enorm_weight_(input=input_embdings, eps=self.eps_, out=input_embdings)
        layer_weight.hnorm_weight_(input=tgt_embdings, eps=self.eps_, out=tgt_embdings)
        cat_embdings = torch.cat((input_embdings, tgt_embdings), dim=-1)

        ans_logics = layer_weight.eh_proj_weight_.mm(cat_embdings)
        return ans_logics

    def _mtp_token_forward(
        self, input_embdings, infer_state: Deepseek2InferStateInfo, layer_weight: Deepseek3MTPPreAndPostLayerWeight
    ):
        tgt_embdings = infer_state.mtp_draft_input_hiddens
        assert input_embdings.shape[0] == tgt_embdings.shape[0]

        layer_weight.enorm_weight_(input=input_embdings, eps=self.eps_, out=input_embdings)
        layer_weight.hnorm_weight_(input=tgt_embdings, eps=self.eps_, out=tgt_embdings)
        cat_embdings = torch.cat((input_embdings, tgt_embdings), dim=-1)

        ans_logics = layer_weight.eh_proj_weight_.mm(cat_embdings)
        return ans_logics

    def context_forward(
        self, input_ids, infer_state: Deepseek2InferStateInfo, layer_weight: Deepseek3MTPPreAndPostLayerWeight
    ):
        input_embdings = super().context_forward(input_ids, infer_state, layer_weight)
        return self._mtp_context_forward(input_embdings, infer_state, layer_weight)

    def token_forward(
        self, input_ids, infer_state: Deepseek2InferStateInfo, layer_weight: Deepseek3MTPPreAndPostLayerWeight
    ):
        input_embdings = super().token_forward(input_ids, infer_state, layer_weight)
        return self._mtp_token_forward(input_embdings, infer_state, layer_weight)

self.cpu_cache_task_status: "InferReq._CpuCacheTaskStatus" = InferReq._CpuCacheTaskStatus.NOT_STARTED

# mtp_step 用来记录一个请求 draft模型每步需要生成的token数量
# 正常模式下，这个值为0，在 mtp 模式下，这个值为 draft 模型每步需要生成的token数量
self.mtp_step: int = get_env_start_args().mtp_step
if self.mtp_step > 0:
    self.decode_need_token_num = self._mtp_decode_need_token_num
else:
    self.decode_need_token_num = self._normal_decode_need_token_num

if g_infer_context.is_linear_att_mixed_model:
    self.get_chuncked_input_token_len = self.get_chuncked_input_token_len_for_linear_att
